import{_ as t,o as r,c as a,a2 as i}from"./chunks/framework.CuteRReP.js";const g=JSON.parse('{"title":"CodyMaster Brain: The Cognitive Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"brain.md","filePath":"brain.md"}'),o={name:"brain.md"};function s(n,e,d,c,l,m){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="codymaster-brain-the-cognitive-architecture" tabindex="-1">CodyMaster Brain: The Cognitive Architecture <a class="header-anchor" href="#codymaster-brain-the-cognitive-architecture" aria-label="Permalink to &quot;CodyMaster Brain: The Cognitive Architecture&quot;">​</a></h1><p>Standard AI systems treat memory as an append-only log, inevitably leading to overloaded context, &quot;goldfish memory&quot;, and recurring hallucinations. <strong>CodyMaster Brain</strong> addresses this by implementing a biomimetic memory architecture inspired by human cognitive processes. It doesn&#39;t just store information; it synthesizes, filters, and selectively forgets.</p><h2 id="the-three-tier-memory-system" tabindex="-1">The Three-Tier Memory System <a class="header-anchor" href="#the-three-tier-memory-system" aria-label="Permalink to &quot;The Three-Tier Memory System&quot;">​</a></h2><p>CodyMaster divides memory processing into three distinct layers, ensuring that the AI has the exact context it needs, explicitly when it needs it.</p><h3 id="_1-working-memory-short-term" tabindex="-1">1. Working Memory (Short-Term) <a class="header-anchor" href="#_1-working-memory-short-term" aria-label="Permalink to &quot;1. Working Memory (Short-Term)&quot;">​</a></h3><p><em>Fast, immediate context for the current session.</em></p><p>Just as humans can only hold about 7 items in short-term memory, CodyMaster utilizes strict working memory limits. Managed primarily by the <strong><a href="/docs/skills/cm-continuity"><code>cm-continuity</code></a></strong> skill, this layer tracks the active task, recent context, and immediate goals using a strict read/update cycle protocol via <code>CONTINUITY.md</code>.</p><ul><li><strong>When to use:</strong> Start of a session to load context, and end of a session to save progress.</li></ul><h3 id="_2-episodic-memory-mid-term" tabindex="-1">2. Episodic Memory (Mid-Term) <a class="header-anchor" href="#_2-episodic-memory-mid-term" aria-label="Permalink to &quot;2. Episodic Memory (Mid-Term)&quot;">​</a></h3><p><em>Experience-based synthesis of problems and solutions.</em></p><p>When tasks are completed, key insights, bug fixes, and architectural decisions are synthesized. If the AI encounters a CORS error and spends 10 minutes fixing it, it records <em>how</em> it was fixed. Next time a similar issue arises in that module, the fix is instantly recalled rather than retrying from scratch.</p><h3 id="_3-semantic-memory-long-term" tabindex="-1">3. Semantic Memory (Long-Term) <a class="header-anchor" href="#_3-semantic-memory-long-term" aria-label="Permalink to &quot;3. Semantic Memory (Long-Term)&quot;">​</a></h3><p><em>Structured, systematized knowledge bases.</em></p><p>Architectural decisions, design system tokens, and core business rules are structured into systematic knowledge bases (like <code>AGENTS.md</code> and <code>stack.json</code>). The <strong><a href="/docs/skills/cm-dockit"><code>cm-dockit</code></a></strong> skill is responsible for systematizing this knowledge so it can be queried efficiently without polluting the working memory.</p><hr><h2 id="biomimetic-mechanisms" tabindex="-1">Biomimetic Mechanisms <a class="header-anchor" href="#biomimetic-mechanisms" aria-label="Permalink to &quot;Biomimetic Mechanisms&quot;">​</a></h2><p>CodyMaster Brain implements dynamic mechanisms to manage the lifecycle of information.</p><h3 id="smart-decay-the-forgetting-curve" tabindex="-1">Smart Decay (The Forgetting Curve) <a class="header-anchor" href="#smart-decay-the-forgetting-curve" aria-label="Permalink to &quot;Smart Decay (The Forgetting Curve)&quot;">​</a></h3><p>Standard AI systems hold onto outdated knowledge forever, leading to bugs when dependencies change. CodyMaster Brain implements a decay mechanism inspired by the <em>Ebbinghaus Forgetting Curve</em>. Outdated libraries, old refactored code patterns, and obsolete learnings literally &quot;decay&quot; and expire mathematically, keeping your active context clean and highly relevant.</p><h3 id="self-healing-feedback-loops" tabindex="-1">Self-Healing Feedback Loops <a class="header-anchor" href="#self-healing-feedback-loops" aria-label="Permalink to &quot;Self-Healing Feedback Loops&quot;">​</a></h3><p>When a bug leads to an infinite loop or a hallucination, CodyMaster Brain recognizes the pattern and &quot;heals&quot; its memory. It records the failure path as a negative constraint, ensuring the exact same mistake is never repeated in future sessions.</p><h3 id="scope-filtering" tabindex="-1">Scope Filtering <a class="header-anchor" href="#scope-filtering" aria-label="Permalink to &quot;Scope Filtering&quot;">​</a></h3><p>Instead of loading a massive <code>memory.txt</code> file on every request, the Brain only loads what is strictly relevant to the current <code>module</code> or <code>file</code>. If there are 50 recorded global learnings, the system uses semantic filtering to load only the 2 or 3 learnings applicable to the current task, saving thousands of tokens per request.</p><hr><h2 id="integrating-core-memory-skills" tabindex="-1">Integrating Core Memory Skills <a class="header-anchor" href="#integrating-core-memory-skills" aria-label="Permalink to &quot;Integrating Core Memory Skills&quot;">​</a></h2><p>To fully utilize the CodyMaster Brain, these core skills should be wired into your standard workflow:</p><table tabindex="0"><thead><tr><th>Skill</th><th>Role in Memory Architecture</th><th>Usage</th></tr></thead><tbody><tr><td>🧠 <strong><a href="/docs/skills/cm-continuity"><code>cm-continuity</code></a></strong></td><td><strong>Working Memory Engine</strong></td><td>Run at the start and end of complex sessions to maintain state across boundaries without bloating the prompt.</td></tr><tr><td>🔍 <strong><a href="/docs/skills/cm-deep-search"><code>cm-deep-search</code></a></strong></td><td><strong>Retrieval Bridge</strong></td><td>When the context exceeds the working memory capacity, this skill intelligently fetches relevant semantic and episodic memory using vector or BM25 search.</td></tr><tr><td>🗄️ <strong><a href="/docs/skills/cm-dockit"><code>cm-dockit</code></a></strong></td><td><strong>Knowledge Organizer</strong></td><td>Run periodically to analyze codebases and generate structured, LLM-readable knowledge bases (<code>AGENTS.md</code>, SOPs) that the brain can rapidly query.</td></tr><tr><td>👑 <strong><a href="/docs/skills/cm-skill-mastery"><code>cm-skill-mastery</code></a></strong></td><td><strong>Meta-Cognition</strong></td><td>Helps the AI &quot;think about thinking,&quot; knowing which memory structures to access, which skills to invoke, and how to sequence them effectively.</td></tr></tbody></table><p>By mirroring human memory systems—prioritizing relevant context, learning from mistakes, and strategically forgetting outdated information—CodyMaster Brain turns the AI from a stateless code generator into a contextual engineering partner.</p>',28)])])}const u=t(o,[["render",s]]);export{g as __pageData,u as default};
